// Tool the model can call: issue_refund({ orderId, amount })
async function issueRefund({ orderId, amount }) {
  // Hard rule, enforced in code -- NOT just requested in the prompt.
  const REFUND_LIMIT = 50;
  if (amount > REFUND_LIMIT) {
    // Reject with a reason the model can relay to the user / escalate.
    return { ok: false, reason: `Refunds over $${REFUND_LIMIT} need human approval.` };
  }
  return processRefund(orderId, amount);
}

