async function runAgentLoop(goal, { maxSteps = 8 } = {}) {
  let state = { goal, history: [] };

  for (let step = 0; step < maxSteps; step++) {
    const decision = await planNextAction(state);      // Perceive + Plan
    if (decision.done) return decision.finalAnswer;

    const observation = await executeTool(decision);    // Act
    state.history.push({ decision, observation });       // Observe
  }
  throw new Error('Agent loop exceeded max steps without completing.');
}

