const CONTEXT_WINDOW_LIMIT = 128000; // tokens, input + output combined

function fitsInContextWindow({ systemPrompt, history, userMessage, maxOutputTokens }) {
  const inputTokens =
    countTokens(systemPrompt) +
    countTokens(history) +
    countTokens(userMessage);

  const totalNeeded = inputTokens + maxOutputTokens;

  if (totalNeeded > CONTEXT_WINDOW_LIMIT) {
    return { fits: false, over: totalNeeded - CONTEXT_WINDOW_LIMIT };
  }
  return { fits: true };
}

function cosineSimilarity(a, b) {
  const dot = a.reduce((sum, ai, i) => sum + ai * b[i], 0);
  const magA = Math.sqrt(a.reduce((s, ai) => s + ai * ai, 0));
  const magB = Math.sqrt(b.reduce((s, bi) => s + bi * bi, 0));
  return dot / (magA * magB);
}

