// Disaggregated evaluation: check model outputs across demographic slices
function evaluateBySubgroup(results) {
  const bySubgroup = groupBy(results, r => r.demographicGroup);
  const metrics = {};
  for (const [group, items] of Object.entries(bySubgroup)) {
    metrics[group] = {
      falsePositiveRate: rate(items, r => r.predicted && !r.actual),
      avgScore: average(items.map(r => r.score))
    };
  }
  // Fail CI if any group deviates beyond threshold from the overall average
  const overallAvg = average(Object.values(metrics).map(m => m.avgScore));
  for (const [group, m] of Object.entries(metrics)) {
    if (Math.abs(m.avgScore - overallAvg) > 0.1) {
      throw new Error(`Bias check failed: ${group} deviates from baseline`);
    }
  }
  return metrics;
}

// Two different fairness metrics on the same predictions -- they can disagree
function demographicParity(preds, group) {
  // Positive prediction rate per group
  return rateBy(preds, group, p => p.predicted === 1);
}

function equalizedOdds(preds, group) {
  // True positive rate and false positive rate per group
  const positives = preds.filter(p => p.actual === 1);
  const negatives = preds.filter(p => p.actual === 0);
  return {
    tprByGroup: rateBy(positives, group, p => p.predicted === 1),
    fprByGroup: rateBy(negatives, group, p => p.predicted === 1)
  };
}

// A model can show equal approval rates (parity) while having very
// different true-positive/false-positive rates per group (failing
// equalized odds) whenever base rates differ across groups.

