async function treeOfThoughts(problem, depth = 3, branching = 3) {
  let current = { thought: problem, score: 0 };
  for (let level = 0; level < depth; level++) {
    const candidates = await generateCandidates(current.thought, branching);
    const scored = await Promise.all(candidates.map(scoreCandidate));
    current = scored.sort((a, b) => b.score - a.score)[0]; // keep the best branch
  }
  return current;
}

async function selfConsistency(prompt, n = 5) {
  const samples = await Promise.all(
    Array.from({ length: n }, () => callModel(prompt, { temperature: 0.7 }))
  );
  const answers = samples.map(extractFinalAnswer);
  const counts = {};
  answers.forEach((a) => (counts[a] = (counts[a] || 0) + 1));
  return Object.entries(counts).sort((a, b) => b[1] - a[1])[0][0]; // majority vote
}

